// Build a complete weather-aware route plan and return a Result.
// points[0] is the origin (boat); the rest are ordered waypoints.
// thresholds carries the tunable warning cutoffs; maxWaypoints bounds API calls.
//
// Returns { ok:true, data:{ speed, startTime, totals, legs } } or
// { ok:false, error:{ code, message } } where code 'INVALID_ROUTE' maps to 400
// and 'ROUTE_WEATHER_API_ERROR' maps to 502 in the handler.
async function planRoute(points: any[], speedKnots: number, startTimeMs: number, thresholds: any, maxWaypoints: number) {
  // --- Validate the route shape and waypoint budget ---
  if (!Array.isArray(points) || points.length < 2) {
    return { ok: false, error: { code: 'INVALID_ROUTE', message: 'A route needs an origin and at least one waypoint.' } };
  }
  const maxWp = (typeof maxWaypoints === 'number' && maxWaypoints > 0) ? maxWaypoints : 12;
  if (points.length - 1 > maxWp) {
    return { ok: false, error: { code: 'INVALID_ROUTE', message: 'Too many waypoints — maximum is ' + maxWp + '.' } };
  }

  // --- Geometry + timing (pure) ---
  const plan: any = functions.call('computeRoutePlan', points, speedKnots, startTimeMs);
  if (!plan) {
    return { ok: false, error: { code: 'INVALID_ROUTE', message: 'Could not compute a route from the given points and speed.' } };
  }
  const legs = plan.legs;

  // --- Fetch weather at each leg destination, in small concurrent batches ---
  // Batching keeps us friendly to Open-Meteo rate limits for long routes.
  const BATCH_SIZE = 4;
  const weatherByLeg: any[] = new Array(legs.length).fill(null);
  let anySuccess = false;
  for (let start = 0; start < legs.length; start += BATCH_SIZE) {
    const slice = legs.slice(start, start + BATCH_SIZE);
    const results = await Promise.all(
      slice.map((leg: any) => functions.call('fetchRouteWeather', leg.to.lat, leg.to.lon))
    );
    results.forEach((r: any, j: number) => {
      if (r && r.ok) { weatherByLeg[start + j] = r.data; anySuccess = true; }
    });
  }

  // A total weather outage is a 502 — but a single failed leg degrades gracefully below
  if (!anySuccess) {
    return { ok: false, error: { code: 'ROUTE_WEATHER_API_ERROR', message: 'Could not fetch weather for any route leg.' } };
  }

  // Convert an Open-Meteo local time string to true UTC ms using the leg's offset.
  // (timezone=auto returns local wall-clock times; appending 'Z' reads them as
  // UTC, then we subtract the offset to recover the real instant.)
  const localIsoToUtcMs = (s: string, offsetSec: number): number | null => {
    if (!s) return null;
    let ms = Date.parse(s + 'Z');
    if (isNaN(ms)) ms = Date.parse(s);
    if (isNaN(ms)) return null;
    return ms - offsetSec * 1000;
  };
  // The local calendar date (YYYY-MM-DD) at a UTC instant for a given offset.
  const localDateOf = (utcMs: number, offsetSec: number) =>
    new Date(utcMs + offsetSec * 1000).toISOString().slice(0, 10);

  // --- Enrich each leg with the arrival-hour conditions + risk warnings ---
  const enrichedLegs = legs.map((leg: any) => {
    const wx = weatherByLeg[leg.index];

    // No weather for this leg — keep geometry, mark conditions unknown
    if (!wx || !Array.isArray(wx.hourly) || wx.hourly.length === 0) {
      return Object.assign({}, leg, {
        conditions: null,
        warnings: [],
        riskLevel: 'ok',
        timezone: wx ? wx.timezone : null
      });
    }

    const offset = wx.utcOffsetSeconds || 0;

    // Find the forecast hour nearest this leg's estimated arrival time
    let bestIdx = 0;
    let bestDiff = Infinity;
    for (let i = 0; i < wx.hourly.length; i++) {
      const hUtc = localIsoToUtcMs(wx.hourly[i].time, offset);
      if (hUtc === null) continue;
      const diff = Math.abs(hUtc - leg.arriveTimeMs);
      if (diff < bestDiff) { bestDiff = diff; bestIdx = i; }
    }
    const hourData = wx.hourly[bestIdx];
    const prevHourData = bestIdx > 0 ? wx.hourly[bestIdx - 1] : null;

    // Resolve sunrise/sunset for the arrival's LOCAL date at the destination
    let sunsetUtcMs: number | null = null;
    let sunriseUtcMs: number | null = null;
    const arriveDate = localDateOf(leg.arriveTimeMs, offset);
    const di = (wx.daily.time || []).indexOf(arriveDate);
    if (di >= 0) {
      sunsetUtcMs = localIsoToUtcMs(wx.daily.sunset[di], offset);
      sunriseUtcMs = localIsoToUtcMs(wx.daily.sunrise[di], offset);
    }

    // Assess risks with the pure warnings function
    const assessment: any = functions.call(
      'computeLegWarnings',
      leg.bearing, hourData, prevHourData, leg.arriveTimeMs, sunsetUtcMs, sunriseUtcMs, thresholds
    );

    return Object.assign({}, leg, {
      conditions: {
        time: hourData.time,
        windSpeed: hourData.windSpeed,
        windDirection: hourData.windDirection,
        windGusts: hourData.windGusts,
        precipitation: hourData.precipitation,
        pressure: hourData.pressure,
        cloudCover: hourData.cloudCover
      },
      sunsetTimeMs: sunsetUtcMs,
      sunriseTimeMs: sunriseUtcMs,
      timezone: wx.timezone,
      warnings: assessment.warnings,
      riskLevel: assessment.riskLevel
    });
  });

  // Success — echo the resolved speed/start alongside totals and enriched legs
  return {
    ok: true,
    data: {
      speed: speedKnots,
      startTime: plan.totals.departTimeMs,
      totals: plan.totals,
      legs: enrichedLegs
    }
  };
}

